const batches = [];
for (let i = 1; i < 2; i++) {
  batches.push({
    json: {
      batchNumber: i,
      batchSize: 5
    }
  });
}
return batches;

const items = $input.all();

return items.map(item => {
  const raw = item.json.response || "";
  let text = raw.trim();

  // Remove markdown fences if present
  text = text
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  // Extract every flat JSON object like { ... }
  const matches = text.match(/\{[^{}]*\}/g);

  if (!matches || matches.length === 0) {
    throw new Error("No JSON objects found in Ollama response:\n" + raw);
  }

  const tasks = [];

  for (const m of matches) {
    let task;
    try {
      task = JSON.parse(m);
    } catch (e) {
      continue;
    }

    // Normalize dueDate to YYYY-MM-DD
    if (task.dueDate && typeof task.dueDate === "string") {
      task.dueDate = task.dueDate.slice(0, 10);
    }

    const cleaned = {
      title: task.title,
      description: task.description ?? "",
      status: task.status,
      priority: task.priority,
    };

    if (task.dueDate) {
      cleaned.dueDate = task.dueDate;
    }

    if (
      cleaned.title &&
      ["OPEN", "IN_PROGRESS", "DONE", "BLOCKED"].includes(cleaned.status) &&
      ["LOW", "MEDIUM", "HIGH"].includes(cleaned.priority)
    ) {
      tasks.push(cleaned);
    }
  }

  if (tasks.length === 0) {
    throw new Error("No valid tasks could be parsed from Ollama response:\n" + raw);
  }

  return {
    json: {
      batchCount: tasks.length,
      tasks
    }
  };
});
